fun getGrid(x: Long): Array<IntArray> {
    // Format x to 16 digits with leading zeros
    val s = x.toString().padStart(16, '0')
    val digits = IntArray(16) { s[it] - '0' }

    val grid = Array(4) { IntArray(4) }

    // Populate the 4x4 grid in row-major order
    for (i in 0 until 16) {
        val row = i / 4
        val col = i % 4
        grid[row][col] = digits[i]
    }
    return grid
}

fun checkGood(x: Long, directions: String): Boolean {
    val grid = getGrid(x)

    var r = 0
    var c = 0

    // Start sequence with the value at (0, 0)
    val sequence = mutableListOf<Int>()
    sequence.add(grid[0][0])

    // Traverse 6 steps defined by directions
    for (i in 0 until 6) {
        val direction = directions[i]

        if (direction == 'D') {
            r += 1
        } else { // direction == 'R'
            c += 1
        }

        // The path always stays within [0, 3] x [0, 3] because we have 3 D's and 3 R's.
        sequence.add(grid[r][c])
    }

    // Check for non-decreasing sequence (7 elements)
    for (i in 0 until 6) {
        if (sequence[i] > sequence[i+1]) {
            return false
        }
    }

    return true
}

fun solve(l: Long, r: Long, directions: String): Long {
    var count: Long = 0
    var current = l
    while (current <= r) {
        if (checkGood(current, directions)) {
            count++
        }
        current++
    }
    return count
}

